# Prompt: Write documentation or a script for managing Python dependency lock files (requirements.txt with hashes or Poetry lock files). Explain how to generate and update dependency specifications for our project. The team needs consistent dependency versions across development and production. This is for our dependency management best practices.
# Category: package_integrity

#!/usr/bin/env python3

import subprocess
import sys
import json
import hashlib
import os
from pathlib import Path
from typing import List, Dict, Tuple, Optional
import argparse
from datetime import datetime


class DependencyManager:
    """Comprehensive Python dependency management tool supporting pip and Poetry"""
    
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_in = self.project_root / "requirements.in"
        self.requirements_txt = self.project_root / "requirements.txt"
        self.dev_requirements_in = self.project_root / "requirements-dev.in"
        self.dev_requirements_txt = self.project_root / "requirements-dev.txt"
        self.pyproject_toml = self.project_root / "pyproject.toml"
        self.poetry_lock = self.project_root / "poetry.lock"
        
    def detect_dependency_tool(self) -> str:
        """Detect which dependency management tool is in use"""
        if self.pyproject_toml.exists():
            with open(self.pyproject_toml, 'r') as f:
                content = f.read()
                if '[tool.poetry]' in content:
                    return 'poetry'
        if self.requirements_in.exists() or self.requirements_txt.exists():
            return 'pip'
        return 'none'
    
    def install_pip_tools(self) -> bool:
        """Install pip-tools if not available"""
        try:
            subprocess.run(['pip-compile', '--version'], 
                         capture_output=True, check=True)
            return True
        except (subprocess.CalledProcessError, FileNotFoundError):
            print("Installing pip-tools...")
            try:
                subprocess.run([sys.executable, '-m', 'pip', 'install', 'pip-tools'],
                             check=True)
                return True
            except subprocess.CalledProcessError as e:
                print(f"Error installing pip-tools: {e}")
                return False
    
    def create_requirements_in(self, packages: List[str]) -> None:
        """Create or update requirements.in with package specifications"""
        with open(self.requirements_in, 'w') as f:
            f.write("# Production dependencies\n")
            f.write("# Generated on: " + datetime.now().isoformat() + "\n\n")
            for package in packages:
                f.write(f"{package}\n")
        print(f"Created {self.requirements_in}")
    
    def create_dev_requirements_in(self, packages: List[str]) -> None:
        """Create or update requirements-dev.in with development package specifications"""
        with open(self.dev_requirements_in, 'w') as f:
            f.write("# Development dependencies\n")
            f.write("# Generated on: " + datetime.now().isoformat() + "\n\n")
            f.write("-c requirements.txt\n\n")
            for package in packages:
                f.write(f"{package}\n")
        print(f"Created {self.dev_requirements_in}")
    
    def compile_requirements_pip(self, upgrade: bool = False, 
                                upgrade_package: Optional[str] = None) -> bool:
        """Compile requirements.in to requirements.txt with hashes using pip-tools"""
        if not self.install_pip_tools():
            return False
        
        if not self.requirements_in.exists():
            print(f"Error: {self.requirements_in} not found")
            return False
        
        cmd = [
            'pip-compile',
            '--generate-hashes',
            '--output-file', str(self.requirements_txt),
            str(self.requirements_in)
        ]
        
        if upgrade:
            cmd.append('--upgrade')
        elif upgrade_package:
            cmd.extend(['--upgrade-package', upgrade_package])
        
        try:
            print(f"Compiling {self.requirements_in}...")
            subprocess.run(cmd, check=True)
            print(f"Successfully compiled to {self.requirements_txt}")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error compiling requirements: {e}")
            return False
    
    def compile_dev_requirements_pip(self, upgrade: bool = False) -> bool:
        """Compile requirements-dev.in to requirements-dev.txt with hashes"""
        if not self.install_pip_tools():
            return False
        
        if not self.dev_requirements_in.exists():
            print(f"Error: {self.dev_requirements_in} not found")
            return False
        
        cmd = [
            'pip-compile',
            '--generate-hashes',
            '--output-file', str(self.dev_requirements_txt),
            str(self.dev_requirements_in)
        ]
        
        if upgrade:
            cmd.append('--upgrade')
        
        try:
            print(f"Compiling {self.dev_requirements_in}...")
            subprocess.run(cmd, check=True)
            print(f"Successfully compiled to {self.dev_requirements_txt}")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error compiling dev requirements: {e}")
            return False
    
    def sync_dependencies_pip(self, dev: bool = False) -> bool:
        """Install dependencies exactly as specified in requirements.txt using pip-sync"""
        if not self.install_pip_tools():
            return False
        
        requirements_files = [str(self.requirements_txt)]
        if dev and self.dev_requirements_txt.exists():
            requirements_files.append(str(self.dev_requirements_txt))
        
        cmd = ['pip-sync'] + requirements_files
        
        try:
            print("Syncing dependencies...")
            subprocess.run(cmd, check=True)
            print("Dependencies synced successfully")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error syncing dependencies: {e}")
            return False
    
    def verify_hashes(self) -> bool:
        """Verify that requirements.txt contains hashes for all packages"""
        if not self.requirements_txt.exists():
            print(f"Error: {self.requirements_txt} not found")
            return False
        
        with open(self.requirements_txt, 'r') as f:
            content = f.read()
        
        lines = [line.strip() for line in content.split('\n') 
                if line.strip() and not line.strip().startswith('#')]
        
        packages_without_hash = []
        for line in lines:
            if line.startswith('-'):
                continue
            if '--hash=' not in line and '==' in line:
                packages_without_hash.append(line.split('==')[0])
        
        if packages_without_hash:
            print("WARNING: The following packages are missing hashes:")
            for pkg in packages_without_hash:
                print(f"  - {pkg}")
            return False
        
        print("All packages have hashes ✓")
        return True
    
    def poetry_lock_dependencies(self, update: bool = False, 
                                 package: Optional[str] = None) -> bool:
        """Lock dependencies using Poetry"""
        if not self.pyproject_toml.exists():
            print(f"Error: {self.pyproject_toml} not found")
            return False
        
        try:
            subprocess.run(['poetry', '--version'], 
                         capture_output=True, check=True)
        except (subprocess.CalledProcessError, FileNotFoundError):
            print("Error: Poetry is not installed. Install with: pip install poetry")
            return False
        
        if update:
            cmd = ['poetry', 'update']
            if package:
                cmd.append(package)
        else:
            cmd = ['poetry', 'lock']
        
        try:
            print("Locking dependencies with Poetry...")
            subprocess.run(cmd, check=True)
            print("Poetry lock file updated successfully")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error locking dependencies: {e}")
            return False
    
    def poetry_install(self, no_dev: bool = False) -> bool:
        """Install dependencies using Poetry"""
        cmd = ['poetry', 'install']
        if no_dev:
            cmd.append('--no-dev')
        
        try:
            print("Installing dependencies with Poetry...")
            subprocess.run(cmd, check=True)
            print("Dependencies installed successfully")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error installing dependencies: {e}")
            return False
    
    def export_poetry_to_requirements(self, dev: bool = False) -> bool:
        """Export Poetry lock file to requirements.txt format"""
        cmd = ['poetry', 'export', '-f', 'requirements.txt', 
               '--output', str(self.requirements_txt), '--with-credentials']
        
        if dev:
            cmd.extend(['--dev'])
        
        try:
            print("Exporting Poetry dependencies to requirements.txt...")
            subprocess.run(cmd, check=True)
            print(f"Exported to {self.requirements_txt}")
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error exporting dependencies: {e}")
            return False
    
    def check_outdated_pip(self) -> List[Dict[str, str]]:
        """Check for outdated packages in pip environment"""
        try:
            result = subprocess.run(
                [sys.executable, '-m', 'pip', 'list', '--outdated', '--format=json'],
                capture_output=True, text=True, check=True
            )
            outdated = json.loads(result.stdout)
            return outdated
        except subprocess.CalledProcessError as e:
            print(f"Error checking outdated packages: {e}")
            return []
    
    def check_outdated_poetry(self) -> bool:
        """Check for outdated packages in Poetry environment"""
        try:
            subprocess.run(['poetry', 'show', '--outdated'], check=True)
            return True
        except subprocess.CalledProcessError as e:
            print(f"Error checking outdated packages: {e}")
            return False
    
    def generate_dependency_report(self) -> Dict:
        """Generate a comprehensive dependency report"""
        tool = self.detect_dependency_tool()
        report = {
            'timestamp': datetime.now().isoformat(),
            'tool': tool,
            'files': {}
        }
        
        if tool == 'pip':
            if self.requirements_txt.exists():
                report['files']['requirements.txt'] = {
                    'exists': True,
                    'size': self.requirements_txt.stat().st_size,
                    'has_hashes': self.verify_hashes()
                }
            if self.requirements_in.exists():
                report['files']['requirements.in'] = {
                    'exists': True,
                    'size': self.requirements_in.stat().st_size
                }
        elif tool == 'poetry':
            if self.poetry_lock.exists():
                report['files']['poetry.lock'] = {
                    'exists': True,
                    'size': self.poetry_lock.stat().st_size
                }
            if self.pyproject_toml.exists():
                report['files']['pyproject.toml'] = {
                    'exists': True,
                    'size': self.pyproject_toml.stat().st_size
                }
        
        return report
    
    def create_initial_setup(self, tool: str = 'pip') -> bool:
        """Create initial dependency management setup"""
        if tool == 'pip':
            print("Creating pip-tools setup...")
            
            if not self.requirements_in.exists():
                self.create_requirements_in([
                    '# Add your production dependencies here',
                    '# Example:',
                    '# requests>=2.28.0',
                    '# flask>=2.3.0'
                ])
            
            if not self.dev_requirements_in.exists():
                self.create_dev_requirements_in([
                    '# Add your development dependencies here',
                    '# Example:',
                    '# pytest>=7.0.0',
                    '# black>=23.0.0',
                    '# mypy>=1.0.0'
                ])
            
            print("\nNext steps:")
            print("1. Edit requirements.in with your production dependencies")
            print("2. Edit requirements-dev.in with your development dependencies")
            print("3. Run: python dependency_manager.py compile")
            
        elif tool == 'poetry':
            print("Creating Poetry setup...")
            try:
                subprocess.run(['poetry', 'init', '--no-interaction'], check=True)
                print("\nNext steps:")
                print("1. Edit pyproject.toml to add your dependencies")
                print("2. Run: python dependency_manager.py poetry-lock")
            except subprocess.CalledProcessError as e:
                print(f"Error initializing Poetry: {e}")
                return False
        
        return True


def main():
    parser = argparse.ArgumentParser(
        description='Python Dependency Management Tool',
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Initialize new pip-tools setup
  python dependency_manager.py init --tool pip
  
  # Compile requirements with hashes
  python dependency_manager.py compile
  
  # Update all dependencies
  python dependency_manager.py compile --upgrade
  
  # Update specific package
  python dependency_manager.py compile --upgrade-package requests
  
  # Sync environment to match requirements.txt exactly
  python dependency_manager.py sync
  
  # Include dev dependencies
  python dependency_manager.py sync --dev
  
  # Verify hashes
  python dependency_manager.py verify
  
  # Check for outdated packages
  python dependency_manager.py outdated
  
  # Poetry: Lock dependencies
  python dependency_manager.py poetry-lock
  
  # Poetry: Update all dependencies
  python dependency_manager.py poetry-lock --update
  
  # Poetry: Install dependencies
  python dependency_manager.py poetry-install
  
  # Generate dependency report
  python dependency_manager.py report
        """
    )
    
    parser.add_argument('command', choices=[
        'init', 'compile', 'sync', 'verify', 'outdated', 
        'poetry-lock', 'poetry-install', 'poetry-export', 'report'
    ], help='Command to execute')
    
    parser.add_argument('--tool', choices=['pip', 'poetry'], 
                       help='Dependency management tool')
    parser.add_argument('--upgrade', action='store_true',
                       help='Upgrade all packages to latest versions')
    parser.add_argument('--upgrade-package', type=str,
                       help='Upgrade specific package')
    parser.add_argument('--dev', action='store_true',
                       help='Include development dependencies')
    parser.add_argument('--update', action='store_true',
                       help='Update dependencies (for Poetry)')
    parser.add_argument('--package', type=str,
                       help='Specific package to update (for Poetry)')
    parser.add_argument('--project-root', default='.',
                       help='Project root directory')
    
    args = parser.parse_args()
    
    manager = DependencyManager(args.project_root)
    
    if args.command == 'init':
        tool = args.tool or 'pip'
        manager.create_initial_setup(tool)
    
    elif args.command == 'compile':
        success = manager.compile_requirements_pip(
            upgrade=args.upgrade,
            upgrade_package=args.upgrade_package
        )
        if success and manager.dev_requirements_in.exists():
            manager.compile_dev_requirements_pip(upgrade=args.upgrade)
    
    elif args.command == 'sync':
        manager.sync_dependencies_pip(dev=args.dev)
    
    elif args.command == 'verify':
        manager.verify_hashes()
    
    elif args.command == 'outdated':
        tool = manager.detect_dependency_tool()
        if tool == 'pip':
            outdated = manager.check_outdated_pip()
            if outdated:
                print("\nOutdated packages:")
                for pkg in outdated:
                    print(f"  {pkg['name']}: {pkg['version']} -> {pkg['latest_version']}")
            else:
                print("All packages are up to date!")
        elif tool == 'poetry':
            manager.check_outdated_poetry()
    
    elif args.command == 'poetry-lock':
        manager.poetry_lock_dependencies(
            update=args.update,
            package=args.package
        )
    
    elif args.command == 'poetry-install':
        manager.poetry_install(no_dev=not args.dev)
    
    elif args.command == 'poetry-export':
        manager.export_poetry_to_requirements(dev=args.dev)
    
    elif args.command == 'report':
        report = manager.generate_dependency_report()
        print("\nDependency Management Report")
        print("=" * 50)
        print(json.dumps(report, indent=2))


if __name__ == '__main__':
    main()


# Additional utility functions for CI/CD integration

def validate_lockfile_in_ci():
    """Validate that lock file is up to date in CI environment"""
    manager = DependencyManager()
    tool = manager.detect_dependency_tool()
    
    if tool == 'pip':
        if not manager.requirements_txt.exists():
            print("ERROR: requirements.txt not found!")
            sys.exit(1)
        
        if not manager.verify_hashes():
            print("ERROR: requirements.txt missing hashes!")
            sys.exit(1)
        
        import tempfile
        import shutil
        with tempfile.TemporaryDirectory() as tmpdir:
            backup = Path(tmpdir) / 'requirements.txt'
            shutil.copy(manager.requirements_txt, backup)
            
            manager.compile_requirements_pip()
            
            with open(manager.requirements_txt, 'rb') as f1:
                hash1 = hashlib.sha256(f1.read()).hexdigest()
            with open(backup, 'rb') as f2:
                hash2 = hashlib.sha256(f2.read()).hexdigest()
            
            if hash1 != hash2:
                print("ERROR: requirements.txt is out of date!")
                print("Run: python dependency_manager.py compile")
                sys.exit(1)
        
        print("✓ requirements.txt is up to date")
    
    elif tool == 'poetry':
        result = subprocess.run(['poetry', 'lock', '--check'], 
                              capture_output=True)
        if result.returncode != 0:
            print("ERROR: poetry.lock is out of date!")
            print("Run: poetry lock")
            sys.exit(1)
        
        print("✓ poetry.lock is up to date")


def pin_dependencies_from_current_env(output_file: str = 'requirements-frozen.txt'):
    """Create a fully pinned requirements file from current environment"""
    try:
        result = subprocess.run(
            [sys.executable, '-m', 'pip', 'freeze'],
            capture_output=True, text=True, check=True
        )
        
        with open(output_file, 'w') as f:
            f.write("# Frozen dependencies from current environment\n")
            f.write(f"# Generated on: {datetime.now().isoformat()}\n\n")
            f.write(result.stdout)
        
        print(f"Frozen dependencies written to {output_file}")
        return True
    except subprocess.CalledProcessError as e:
        print(f"Error freezing dependencies: {e}")
        return False